B.aiy=new A.h3("Fikri M\xfclkiyet",null)
B.ai1=new A.fN("Uygulama ve i\xe7eri\u011fi Evlumba Software'a aittir. AI taraf\u0131ndan \xfcretilen \xe7\xf6z\xfcmler e\u011fitim ama\xe7l\u0131d\u0131r ve do\u011frulu\u011fu garanti edilmez.",null)
